"""matplotlib.table — table drawing stubs."""

from matplotlib.artist import Artist


class Cell(Artist):
    def __init__(self, xy, width, height, *, edgecolor='k', facecolor='w',
                 fill=True, text='', loc='right', fontproperties=None, visible_edges='closed'):
        super().__init__()
        self._xy = xy
        self._width = width
        self._height = height
        self._text = text
        self._loc = loc

    def get_text(self): return self._text
    def set_text_props(self, **kwargs): pass
    def get_path(self): return None
    def set_fontsize(self, size): pass
    def get_fontsize(self): return 12
    def auto_set_font_size(self, renderer): pass


class Table(Artist):
    codes = {'best': 0, 'upper right': 1, 'upper left': 2, 'lower left': 3,
             'lower right': 4, 'center left': 5, 'center right': 6,
             'lower center': 7, 'upper center': 8, 'center': 9}

    def __init__(self, ax, loc=None, bbox=None, **kwargs):
        super().__init__()
        self.ax = ax
        self._cells = {}
        self._loc = loc

    def add_cell(self, row, col, *args, **kwargs):
        cell = Cell((0, 0), 1, 1, **kwargs)
        self._cells[(row, col)] = cell
        return cell

    def __getitem__(self, position):
        return self._cells.get(position)

    def __setitem__(self, position, cell):
        self._cells[position] = cell

    def edges(self): pass
    def auto_set_font_size(self, value=True): pass
    def auto_set_column_width(self, col): pass
    def scale(self, xscale, yscale): pass
    def set_fontsize(self, size): pass
    def get_celld(self): return self._cells


def table(ax, cellText=None, cellColours=None, cellLoc='right', colWidths=None,
          rowLabels=None, rowColours=None, rowLoc='left',
          colLabels=None, colColours=None, colLoc='center',
          loc='bottom', bbox=None, edges='closed', **kwargs):
    return Table(ax, loc=loc, bbox=bbox)
